var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까…… 그 노바급 리액터라는 걸 샬롯이 훔쳐갔다는 거야?","JPN":"つまり……そのノヴァ級リアクターってものをシャーロットが盗んだってこと？","ENG":"So... Carlota stole the Nova-Class Reactor?","TWN":"意思就是……夏洛特把那個叫諾瓦反應爐的東西搶走了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 어디에 쓸지는 몰라도 그렇게 좋은 목적은 아니겠지.","JPN":"そうだ。何に使うつもりかわからないが、きっといい目的ではないだろう。","ENG":"Yes. We don’t know why, but I don’t think she will put it to good use.","TWN":"沒錯，雖然不知道用途為何，但肯定不是什麼好事！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그러고 보니 아가씨의 피도 추출해 갔다고?","JPN":"そういえば、嬢ちゃんの血も抜いて行ったらしいな？","ENG":"And Carlota took your blood as well?","TWN":"而且她還抽你的血？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 뭔가 보석처럼 가공해서 가져갔어.","JPN":"うん。宝石みたいに加工して持って行ったよ。","ENG":"Yes. She crystallized my blood and took it away.","TWN":"嗯，她把我的血加工成類似寶石的東西。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 말을 들으니 더 불안해지는군.","JPN":"それを聞いたらますます不安になってきた。","ENG":"Okay, that makes me very nervous.","TWN":"聽你這麼說我又更不安了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 기억하기로 아가씨의 피는 보통 피가 아니었던 것 같은데.","JPN":"俺の記憶が正しければ、嬢ちゃんの血は特別なものだった気がするんだが。","ENG":"If I remember it correctly, your blood is not ordinary, right?","TWN":"我記得，你的血應該不是普通的血吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"맞습니다. 성분이 아주 유니크하죠.","JPN":"そうです。成分がとてもユニークなんですよ。","ENG":"Yes, it’s very unique indeed.","TWN":"是的，成分非常特殊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나, 남의 피 가지고 함부로 떠들지 마! 부끄럽게!","JPN":"ひ、人の血を勝手にユニークだなんて言わないでよ！　恥ずかしいな！","ENG":"S-stop talking about my blood, you’re embarrassing me!","TWN":"不要在那邊討論我的血啦！很害羞欸！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 아저씨, 내가 이걸 물어봐도 될지 모르겠는데……. 저 사람 분명…….","JPN":"ところでおじさん、聞いてもいいのかわからないけど……あの人って……","ENG":"Um, Mr. Mason, I’m not sure if I should be asking you about this... But is she...?","TWN":"大叔，有個問題我不知道該不該問……她是那個……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 리플레이서 퀸이 맞아.","JPN":"ああ、リプレイサー・クイーンだ。","ENG":"Yes, she was the Replacer Queen.","TWN":"沒錯，就是克隆·女皇。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금은 제이나 크로펠이라는 델타 세븐 요원이라고 하지만 말이야.","JPN":"今はジェイナ・クロペルという名のデルタセブン要員だけどな。","ENG":"But she is now Jaina Kropel, one of the Delta Seven agents.","TWN":"但是她現在叫作婕娜·克洛佩爾，是第七三角洲部隊的隊員。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말 그 퀸이라고? 그 여자가 왜 아저씨랑 같이 다니는 거야?","JPN":"本当にあのクイーンなの？　あの女がどうしておじさんと一緒にいるの？","ENG":"So she really is the Queen? Why is she with you?","TWN":"她真的是那個女皇喔？你們怎麼會一起行動？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 퀸은…… 아저씨네 형의 원수 아니었어?","JPN":"リプレイサー・クイーンは……おじさんのお兄さんの仇じゃなかった？","ENG":"The Replacer Queen... She killed your brother, didn’t she?","TWN":"克隆·女皇……不是害死你哥哥的兇手嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……나도 아직 마음이 정리된 게 아니라 대답하기 어렵군.","JPN":"……俺もまだ気持ちの整理がついていないから、答えにくいな。","ENG":"I can’t really explain, because I’m still confused myself.","TWN":"……我自己也還沒整理好心情，不知道該怎麼回答你。"},"stage":{"bg":"MAINSTREAM_5503010","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"확실한 건 리플레이서 사태 때 내 복수는 완성되었다는 거야.","JPN":"確実に言えることは、リプレイサー事件の時に俺の復讐は終わったということだ。","ENG":"But one thing I’m certain of is that I did take revenge for my brother during the Replacer incident.","TWN":"但我能確定的是，克隆集團事件時，我就已經算是報仇了。"},"stage":{"bg":"MAINSTREAM_5503010","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저기 있는 제이나 크로펠은……. 일종의 복제인간 같은 거지.","JPN":"あそこにいるジェイナ・クロペルは……一種のクローン人間のようなものさ。","ENG":"That Jaina Kropel is... like a clone.","TWN":"這位婕娜·克洛佩爾……就類似複製人的概念。"},"stage":{"bg":"MAINSTREAM_5503010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};